import { useState } from "react";
import SpeakBtn from "../SpeakBtn";

export default function PhrasesSection({ phrases, onDone, done }) {
  const [revealed, setRevealed] = useState({});

  return (
    <div className="fade-in space-y-3">
      {phrases.map((p, i) => (
        <div key={i} className="bg-[#221f35] border border-gray-700 rounded-2xl p-4 hover:border-gray-600  transition-all">
          <div className="flex items-start justify-between gap-3">
            <div className="flex-1">
              <p className="text-base font-extrabold ">"{p.phrase}"</p>
              <p className="text-xs text-slate-400 mt-1 italic">{p.usage}</p>

              <button onClick={() => setRevealed((r) => ({ ...r, [i]: !r[i] }))}
                className="mt-2 text-xs text-indigo-600 font-bold hover:underline flex items-center gap-1">
                {revealed[i] ? "🙈 Hide Bangla" : "👁 Show Bangla meaning"}
              </button>
              {revealed[i] && (
                <div className="mt-1.5 fade-in text-sm font-bold text-pink-600 bg-pink-50 border border-pink-100 px-3 py-1.5 rounded-lg">
                  🇧🇩 {p.bangla}
                </div>
              )}

              <div className="mt-3 flex items-start gap-2">
                <SpeakBtn text={p.example} size="sm" />
                <p className="text-sm text-slate-700 italic mt-0.5">"{p.example}"</p>
              </div>
            </div>
            <SpeakBtn text={p.phrase} />
          </div>
        </div>
      ))}

      {!done ? (
        <div className="flex justify-end mt-5">
          <button onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5">
            Mark as Done ✓
          </button>
        </div>
      ) : <p className="text-right text-green-700 font-bold text-sm mt-4">✓ Phrases completed!</p>}
    </div>
  );
}
